import json
import logging
from google.cloud import storage, firestore, pubsub_v1
from google.cloud.exceptions import NotFound
import os

def process_file_and_write_to_firestore(request):
    """Google Cloud Function to process files from Cloud Storage, write to Firestore, and publish to Pub/Sub"""
    
    # Get environment variables
    bucket_name = os.environ.get('BUCKET_NAME')
    topic_name = os.environ.get('TOPIC_NAME')
    
    # Validate required environment variables
    if not bucket_name or not topic_name:
        logging.error("Missing required environment variables")
        return ("Missing required environment variables", 400)
    
    # Initialize clients
    storage_client = storage.Client()
    firestore_client = firestore.Client()
    pubsub_client = pubsub_v1.PublisherClient()
    
    # Get the request data
    if request.method == 'POST':
        try:
            # Handle JSON payload
            request_json = request.get_json(silent=True)
            if not request_json:
                return ("Invalid JSON payload", 400)
            
            # Process file from Cloud Storage
            file_name = request_json.get('file_name')
            if not file_name:
                return ("Missing file_name in payload", 400)
            
            # Get the bucket and blob
            bucket = storage_client.bucket(bucket_name)
            blob = bucket.blob(file_name)
            
            # Check if file exists
            if not blob.exists():
                return (f"File {file_name} not found in bucket {bucket_name}", 404)
            
            # Download file content
            file_content = blob.download_as_text()
            
            # Process content (example: count words)
            word_count = len(file_content.split())
            
            # Write to Firestore
            try:
                collection_ref = firestore_client.collection('processed_files')
                doc_ref = collection_ref.document(file_name)
                doc_ref.set({
                    'file_name': file_name,
                    'word_count': word_count,
                    'processed_at': firestore.SERVER_TIMESTAMP,
                    'content_preview': file_content[:100] + '...' if len(file_content) > 100 else file_content
                })
            except Exception as e:
                logging.error(f"Firestore write error: {str(e)}")
                return (f"Firestore write failed: {str(e)}", 500)
            
            # Publish to Pub/Sub
            try:
                topic_path = pubsub_client.topic_path(os.environ.get('PROJECT_ID'), topic_name)
                message_data = {
                    'file_name': file_name,
                    'word_count': word_count,
                    'processed_at': firestore.SERVER_TIMESTAMP
                }
                publish_future = pubsub_client.publish(
                    topic_path,
                    json.dumps(message_data).encode('utf-8')
                )
                publish_future.result()
            except Exception as e:
                logging.error(f"Pub/Sub publish error: {str(e)}")
                return (f"Pub/Sub publish failed: {str(e)}", 500)
            
            return ("Successfully processed file", 200)
            
        except Exception as e:
            logging.error(f"Error processing file: {str(e)}")
            return (f"Error processing file: {str(e)}", 500)
    
    else:
        return ("Method not allowed", 405)

